const feeds = [
  $('Fetch TechCrunch AI').first().json,
  $('Fetch VentureBeat AI').first().json,
  $('Fetch HN Top').first().json
];

const allStories = [];
const now = new Date();
const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000);

for (const feed of feeds) {
  const text = typeof feed === 'string' ? feed : (feed.data || feed.body || JSON.stringify(feed));
  const items = text.match(/<item[\s\S]*?<\/item>/gi) || [];

  for (const item of items) {
    const titleMatch = item.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i);
    const descMatch = item.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/i);
    const linkMatch = item.match(/<link[^>]*>(.*?)<\/link>/i);
    const dateMatch = item.match(/<pubDate[^>]*>(.*?)<\/pubDate>/i);

    if (titleMatch) {
      const pubDate = dateMatch ? new Date(dateMatch[1]) : now;
      if (pubDate >= oneDayAgo) {
        allStories.push({
          title: titleMatch[1].replace(/<[^>]*>/g, '').trim(),
          summary: descMatch ? descMatch[1].replace(/<[^>]*>/g, '').trim().substring(0, 300) : '',
          link: linkMatch ? linkMatch[1].trim() : '',
          date: pubDate.toISOString()
        });
      }
    }
  }
}

const top5 = allStories.slice(0, 5);

return top5.map(story => ({ json: story }));

const story = $input.first().json;

return [{
  json: {
    systemPrompt: `Write LinkedIn posts for John, founder of IntraWeb Technologies. Voice: builder not talker, engineering-first, contrarian with specifics. No buzzwords, no corporate speak, no em dashes. No 'I\'ve been thinking', no context-setting openers. Structure: Problem > Insight > Framework > Takeaway. 700-900 characters. 3-5 hashtags at bottom only. Forced-choice CTA. 0-1 emojis. Never use: game-changer, revolutionize, leverage, excited to share, delve, in today\'s world. Return JSON only: { "hook": "", "full_post": "", "hashtags": "", "suggested_link": "", "news_source": "" }`,
    userPrompt: `Headline: ${story.title}\nSummary: ${story.summary}\nSource: ${story.link}\n\nWrite a contrarian take, not a summary.`,
    maxTokens: 1500
  }
}];

const result = $('Generate Post').first().json;
const config = $('Get Config').first().json;
let postData;

try {
  postData = JSON.parse(result.data.text);
} catch(e) {
  postData = {
    hook: result.data.text.substring(0, 100),
    full_post: result.data.text,
    hashtags: '',
    suggested_link: '',
    news_source: ''
  };
}

return [{
  json: {
    sheetId: config.google.masterSheetId,
    dateGenerated: new Date().toISOString(),
    newsHook: postData.hook || '',
    fullPost: postData.full_post || '',
    hashtags: postData.hashtags || '',
    suggestedLink: postData.suggested_link || '',
    status: 'draft',
    scheduledTime: '',
    postNotes: `Source: ${postData.news_source || ''}`
  }
}];

const config = $('Get Config').first().json;

return [{
  json: {
    message: `LinkedIn drafts ready for review: https://docs.google.com/spreadsheets/d/${config.google.masterSheetId}`,
    priority: 'info'
  }
}];

return [{
  json: {
    workflowName: 'SYS 06 — LinkedIn Content Pipeline',
    contactName: '',
    phone: '',
    eventType: 'content_generated',
    status: 'success',
    notes: 'LinkedIn drafts generated from RSS feeds'
  }
}];
